        n = len(nums)

        # Compute maximal strictly-increasing prefix lengths:
        # inc_pref[i] = True iff nums[0..i] is strictly increasing
        inc_pref = [False] * n
        inc_pref[0] = True
        for i in range(1, n):
            inc_pref[i] = inc_pref[i - 1] and (nums[i - 1] < nums[i])

